{"vars":[{"line":1,"kind":12,"name":"pod"},{"name":"This","kind":12,"line":1},{"line":1,"name":"file","kind":12},{"line":1,"name":"is","kind":12},{"kind":12,"name":"of","line":1},{"line":1,"name":"excellent","kind":12},{"line":1,"kind":12,"name":"Frew","containerName":"s::DBIx::Class::Helpers"},{"line":1,"name":"but","kind":12},{"kind":12,"name":"is","line":1},{"name":"used","kind":12,"line":1},{"kind":12,"name":"to","line":2},{"line":2,"kind":12,"name":"provide"},{"kind":12,"name":"concatentation","line":2},{"name":"function","kind":12,"line":2},{"line":2,"name":"It","kind":12},{"line":2,"name":"would","kind":12},{"name":"be","kind":12,"line":2},{"name":"nice","kind":12,"line":2},{"line":2,"name":"to","kind":12},{"line":2,"kind":12,"name":"release"},{"line":2,"name":"this","kind":12},{"name":"separately","kind":12,"line":2},{"kind":12,"name":"but","line":3},{"line":3,"kind":12,"name":"the"},{"line":3,"name":"being","kind":12},{"line":3,"kind":12,"name":"this"},{"line":3,"kind":12,"name":"file"},{"line":3,"name":"only","kind":12},{"kind":12,"name":"remains","line":3},{"name":"copyright","kind":12,"line":3},{"line":3,"kind":12,"name":"by"},{"name":"Arthur","kind":12,"line":3},{"name":"Axel","kind":12,"line":4},{"line":4,"kind":12,"name":"Schmidt"},{"line":6,"kind":12,"name":"The"},{"line":6,"name":"original","kind":12},{"line":6,"name":"licence","kind":12},{"kind":12,"name":"this","line":6},{"name":"file","kind":12,"line":6},{"name":"only","kind":12,"line":6},{"line":6,"kind":12,"name":"is"},{"kind":12,"name":"This","line":7},{"line":7,"name":"is","kind":12},{"line":7,"kind":12,"name":"free"},{"line":7,"name":"software","kind":12},{"line":7,"name":"you","kind":12},{"line":7,"kind":12,"name":"can"},{"kind":12,"name":"redistribute","line":7},{"name":"it","kind":12,"line":7},{"kind":13,"name":";\n            return $self->result_source->storage->sql_maker->_quote($thing)\n        }\n        else {\n            my ($func, $thing2) = %$thing;\n            return \"$func(\".$self->_flatten_thing($thing2).\")\";\n        }\n    }\n\n    return ${$thing} if $ref eq 'SCALAR';\n\n    return @{${$thing}};\n}\n\nsub _introspector_concat # Do not conflict with _introspector in DBIx::Class::Helper::*\n{\n    my $d = DBIx::Introspector->new(drivers => '2013-12.01');\n\n    SQLITE: {\n        $d->decorate_driver_unconnected(SQLite =>\n            concat => sub {\n                sub {\n                    my @fields = map { \"COALESCE($_, '')\" } @_;\n                    [ join ' || ', @fields ];\n                },\n            }\n        );\n        $d->decorate_driver_unconnected(SQLite =>\n            least => sub {\n                sub {\n                    # Under some circumstances, sqlite doesn't like only one\n                    # value in a MIN()\n                    return [ $_[0] ] if @_ == 1;\n                    # Aghhhh, Sqlite returns NULL for a MIN() if any one of the\n                    # values is a NULL (unlike its aggregate function MIN and\n                    # the equivalent Pg function\n                    my $fields = join ', ', map \"COALESCE($_, '9999-12-31')\", @_;\n                    [ \"MIN( $fields )\" ];\n                },\n            }\n        );\n        $d->decorate_driver_unconnected(SQLite =>\n            greatest => sub {\n                sub {\n                    return [ $_[0] ] if @_ == 1;\n                    # See comment above\n                    my $fields = join ', ', map \"COALESCE($_, '0000-01-01')\", @_;\n                    [ \"MAX( $fields )\" ];\n                },\n            }\n        );\n    }\n\n    PG: {\n        $d->decorate_driver_unconnected(Pg =>\n            concat => sub {\n                sub {\n                    my $fields = join ', ', @_;\n                    [ \"CONCAT( $fields )\" ];\n                },\n            }\n        );\n        $d->decorate_driver_unconnected(Pg =>\n            least => sub {\n                sub {\n                    my $fields = join ', ', @_;\n                    [ \"LEAST( $fields )\" ];\n                },\n            }\n        );\n        $d->decorate_driver_unconnected(Pg =>\n            greatest => sub {\n                sub {\n                    my $fields = join ', ', @_;\n                    [ \"GREATEST( $fields )\" ];\n                },\n            }\n        );\n    }\n\n    MYSQL: {\n        $d->decorate_driver_unconnected(mysql =>\n            concat => sub {\n                sub {\n                    my $fields = join ', ', @_;\n                    [ \"CONCAT( $fields )\" ];\n                },\n            }\n        );\n        $d->decorate_driver_unconnected(mysql =>\n            least => sub {\n                sub {\n                    my $fields = join ', ', @_;\n                    [ \"LEAST( $fields )\" ];\n                }\n            }\n        );\n        $d->decorate_driver_unconnected(mysql =>\n            greatest => sub {\n                sub {\n                    my $fields = join ', ', @_;\n                    [ \"GREATEST( $fields )\" ];\n                }\n            }\n        );\n    }\n\n    return $d;\n}\n\nsub _helper\n{   my ($self, $type, @things) = @_;\n\n    $type eq 'concat' || $type eq 'least' || $type eq 'greatest'\n        or panic \"Invalid type $type\";\n\n    my $storage = $self->result_source->storage;\n    $storage->ensure_connected;\n\n    my $d = _introspector_concat();\n\n    @things = map { _flatten_thing $self, $_ } @things;\n\n    return \\(\n        $d->get($storage->dbh, undef, $type)->(\n            @things\n        )\n    );\n}\n\nsub helper_concat\n{   my $self = shift;\n    $self->_helper('concat', @_);\n}\n\nsub helper_least\n{   my $self = shift;\n    $self->_helper('least', @_);\n}\n\nsub helper_greatest\n{   my $self = shift;\n    $self->_helper('greatest', @_);\n}\n\n1;\n","containerName":null,"line":180}],"version":5}